  const [editHistory, setEditHistory] = useState([]); // Track edit history: [{ rowId, rowName, kpi, timeIndex, timeLabel, oldValue, newValue, adjustmentNote, timestamp }]
  const [editingCell, setEditingCell] = useState(null); // Currently editing cell: { rowId, kpi, timeIndex }
  const [undoStack, setUndoStack] = useState([]); // Stack of operations: [{ changes: [{ key, oldValue, newValue }], timestamp }]
  const [redoStack, setRedoStack] = useState([]); // Stack of operations for redo

  // Recursive function to remove all aggregate rows in Account Manager View
  // This function is reused across multiple data processing locations
  const removeAggregateRows = (rows) => {
    if (!Array.isArray(rows)) return [];
    return rows.flatMap(row => {
      if (!row) return [];
      
      // Helper function to check if a row is an aggregate row
      const isAggregateRow = (r) => {
        if (!r || !r.id) return false;
        return r.id === 'aggregate' || 
               r.id === 'total-aggregate' || 
               (typeof r.id === 'string' && r.id.startsWith('aggregate-'));
      };
      
      // For Account Manager View, remove all aggregate rows recursively
      if (selectedKAMView === 'Account Manager View') {
        // If this is an aggregate row, recursively process its children
        if (isAggregateRow(row)) {
          if (row.children && Array.isArray(row.children)) {
            return removeAggregateRows(row.children); // Recursively remove aggregates from children
          }
          return [];
        }
        // If row has children, recursively check and clean them
        if (row.children && Array.isArray(row.children)) {
          return [{
            ...row,
            children: removeAggregateRows(row.children)
          }];
        }
      } else {
        // For Account Director View, keep North America but remove other aggregate rows
        if (isAggregateRow(row) && 
            row.name && row.name.includes('MagnaDrive North America')) {
          return [row];
        }
        // If this is an aggregate row (but not North America), return its children instead
        if (isAggregateRow(row)) {
          if (row.children && Array.isArray(row.children)) {
            return removeAggregateRows(row.children);
          }
          return [];
        }
        // If row has children, recursively check and clean them
        if (row.children && Array.isArray(row.children)) {
          return [{
            ...row,
            children: removeAggregateRows(row.children)
          }];
        }
      }
      // Otherwise, keep the row
      return [row];
    });
  };
  const [isUndoRedoInProgress, setIsUndoRedoInProgress] = useState(false); // Flag to prevent saving to undo stack during undo/redo
  const [adjustmentNote, setAdjustmentNote] = useState(''); // Adjustment note for current edit
