  const [columnFilters, setColumnFilters] = useState({}); // Track filter criteria for each column: { 'kpi:Baseline...': { operator: '>=', value: '1000' }, 'time:0': { operator: '=', value: '500' } }
  const [hierarchyFilter, setHierarchyFilter] = useState(''); // Filter for hierarchy/name column (product/category/account names) - DEPRECATED for Time Series, use hierarchyFilterType and hierarchyFilterSearchValue
  const [hierarchyFilterType, setHierarchyFilterType] = useState('Dimensions'); // 'KPI' or 'Dimensions' - for Time Series view only
  const [hierarchyFilterSearchValue, setHierarchyFilterSearchValue] = useState(''); // Search value for KPI or Dimensions filtering in Time Series view
  const [hierarchyFilterComboboxOpen, setHierarchyFilterComboboxOpen] = useState(false); // Whether the hierarchy filter combobox dropdown is open
  const [timeHierarchyFilter, setTimeHierarchyFilter] = useState(''); // Filter for time hierarchy in Time Roll-up view (FY, Quarters, Months) - DEPRECATED, use dimensionsFilterType and dimensionsFilterSearchValue
  // Dimensions view filter state
  const [dimensionsFilterType, setDimensionsFilterType] = useState('Time'); // 'Time' or 'Dimensions' - for Dimensions view only
  const [dimensionsFilterSearchValue, setDimensionsFilterSearchValue] = useState(''); // Search value for Time or Dimensions filtering in Dimensions view
